import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { productsAPI, categoriesAPI } from '../services/api';
import ProductCard from '../components/common/ProductCard';

export default function Home() {
  const [products, setProducts] = useState([]);
  const [categories, setCategories] = useState([]);

  useEffect(() => {
    productsAPI.getAll({ limit: 8 }).then(({ data }) => setProducts(data.products));
    categoriesAPI.getAll().then(({ data }) => setCategories(data));
  }, []);

  return (
    <>
      <section className="hero">
        <div className="container">
          <h1>Descubre los mejores productos</h1>
          <p>Calidad, variedad y los mejores precios en un solo lugar</p>
          <Link to="/catalog" className="btn btn-secondary btn-lg">Ver catálogo →</Link>
        </div>
      </section>

      <div className="page">
        <div className="container">
          {/* Categories */}
          <h2 style={{ marginBottom: '1.5rem', fontSize: '1.5rem', fontWeight: 800 }}>Categorías</h2>
          <div className="grid grid-4" style={{ marginBottom: '3rem' }}>
            {categories.map((cat) => (
              <Link
                key={cat.id}
                to={`/catalog?categoryId=${cat.id}`}
                className="card"
                style={{ padding: '1.5rem', textAlign: 'center', fontWeight: 700, color: 'var(--primary)', transition: 'transform .2s' }}
                onMouseEnter={(e) => e.currentTarget.style.transform = 'translateY(-4px)'}
                onMouseLeave={(e) => e.currentTarget.style.transform = 'none'}
              >
                📦 {cat.name}
              </Link>
            ))}
          </div>

          {/* Featured products */}
          <h2 style={{ marginBottom: '1.5rem', fontSize: '1.5rem', fontWeight: 800 }}>Productos destacados</h2>
          <div className="grid grid-4">
            {products.map((p) => <ProductCard key={p.id} product={p} />)}
          </div>
        </div>
      </div>
    </>
  );
}
